export const 散雲符 = (bi) => {
    const u = bi.u, k = 2.55;
    const X = (c) => (c - 3.6) * k;
    const Z = (r) => (r - 5.0) * k + 1.0;
    const 線 = (書, 寬 = 0.62) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 出 = (書, 寬 = 0.65) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '出' }, 書);
    const 點 = (x, z, r = 0.42) => bi.塊(p => p.M(X(x - r), Z(z)).C(X(x - r), Z(z - r * 1.3), X(x + r), Z(z - r * 1.3), X(x + r), Z(z))
        .C(X(x + r), Z(z + r * 1.3), X(x - r), Z(z + r * 1.3), X(x - r), Z(z)).close());
    // 雨冠
    線(p => p.M(X(0.2), Z(5.25)).L(X(7.1), Z(5.18)), 0.8);
    出(p => p.M(X(0.35), Z(5.30)).L(X(0.33), Z(17.11)).C(X(0.32), Z(17.65), X(0.22), Z(18.05), X(0.08), Z(18.32)), 0.7);
    出(p => p.M(X(6.85), Z(5.30)).L(X(6.83), Z(16.30)).C(X(6.85), Z(16.84), X(6.95), Z(17.25), X(7.1), Z(17.52)), 0.7);
    線(p => p.M(X(0.9), Z(6.10)).L(X(2.5), Z(6.06)), 0.55);
    線(p => p.M(X(0.9), Z(6.70)).L(X(2.5), Z(6.66)), 0.55);
    線(p => p.M(X(0.9), Z(7.30)).L(X(2.5), Z(7.26)), 0.55);
    線(p => p.M(X(4.2), Z(6.10)).C(X(5.00), Z(5.94), X(5.40), Z(6.02), X(5.8), Z(6.14)), 0.55);
    線(p => p.M(X(4.2), Z(6.70)).C(X(5.00), Z(6.54), X(5.40), Z(6.62), X(5.8), Z(6.74)), 0.55);
    線(p => p.M(X(4.2), Z(7.30)).C(X(5.00), Z(7.14), X(5.40), Z(7.22), X(5.8), Z(7.34)), 0.55);
    線(p => p.M(X(3.5), Z(5.35)).L(X(3.48), Z(7.80)), 0.6);
    // 出出疊
    線(p => p.M(X(3.5), Z(8.00)).L(X(3.48), Z(10.09)), 0.55);
    線(p => p.M(X(2.0), Z(8.74)).L(X(1.98), Z(10.09)), 0.55);
    線(p => p.M(X(5.0), Z(8.74)).L(X(4.98), Z(10.09)), 0.55);
    線(p => p.M(X(1.6), Z(10.09)).L(X(5.4), Z(10.04)), 0.55);
    線(p => p.M(X(3.5), Z(10.50)).L(X(3.48), Z(12.66)), 0.55);
    線(p => p.M(X(2.0), Z(11.30)).L(X(1.98), Z(12.66)), 0.55);
    線(p => p.M(X(5.0), Z(11.30)).L(X(4.98), Z(12.66)), 0.55);
    線(p => p.M(X(1.6), Z(12.66)).L(X(5.4), Z(12.60)), 0.55);
    // 乙曲對
    出(p => p.M(X(2.2), Z(13.20)).C(X(1.8), Z(13.87), X(2.2), Z(14.41), X(2.8), Z(14.27)), 0.55);
    出(p => p.M(X(4.6), Z(13.20)).C(X(4.2), Z(13.87), X(4.6), Z(14.41), X(5.2), Z(14.27)), 0.55);
    // 皿框（內豎二承底橫）
    線(p => p.M(X(1.6), Z(15.09)).L(X(1.6), Z(17.65)).L(X(5.8), Z(17.58)).L(X(5.8), Z(15.02)).L(X(1.55), Z(15.09)), 0.55);
    線(p => p.M(X(2.9), Z(15.15)).L(X(2.88), Z(17.58)), 0.5);
    線(p => p.M(X(4.5), Z(15.09)).L(X(4.48), Z(17.52)), 0.5);
    線(p => p.M(X(1.5), Z(18.12)).L(X(5.9), Z(18.05)), 0.55);
    // 雙小勾承中垂
    出(p => p.M(X(2.0), Z(18.73)).C(X(1.7), Z(19.41), X(2.0), Z(19.95), X(2.5), Z(19.88)), 0.55);
    出(p => p.M(X(3.6), Z(18.87)).C(X(3.3), Z(19.54), X(3.6), Z(20.08), X(4.1), Z(20.01)), 0.55);
    出(p => p.M(X(3.6), Z(20.48)).L(X(3.58), Z(21.70)), 0.62);
    點(3.6, 22.78);
};
